export const totalResources = 156;

export function getSectionById(id: string): Section | undefined {
  return sections.find((s) => s.id === id);
}

export function getSectionsByCategory(category: string): Section[] {
  return sections.filter((s) => s.category === category);
}

export function getResourceById(resourceId: string): { resource: ResourceItem; section: Section } | undefined {
  for (const section of sections) {
    const resource = section.resources.find((r) => r.id === resourceId);
    if (resource) return { resource, section };
  }
  return undefined;
}
